{
  "global": "Fix the locale catalog search order in Sphinx so that user-configured locale_dirs are searched before the built-in Sphinx locale directory, allowing project-level translations to override shipped ones.",
  "subtasks": [
    {
      "subtask": "Locate the code responsible for loading and merging gettext translation catalogs",
      "atomics": [
        "Search sphinx/locale/__init__.py and sphinx/application.py for init_locale, get_translation, and catalog-loading functions",
        "Identify where locale_dirs from conf.py are collected and in what order they are passed to the gettext/Babel catalog chain"
      ]
    },
    {
      "subtask": "Trace the exact search order that causes built-in sphinx locale to win over user locale_dirs",
      "atomics": [
        "Find where the built-in sphinx/locale directory is appended or prepended relative to user locale_dirs",
        "Confirm that the first catalog found wins (or that merge order determines priority) so the bug is a simple ordering issue"
      ]
    },
    {
      "subtask": "Fix the ordering so user locale_dirs are consulted first and can override built-in translations",
      "atomics": [
        "In the function that builds the list of locale search paths, move user-supplied locale_dirs before the built-in sphinx locale path",
        "Ensure the fix applies to all catalog-loading call sites (e.g., both main sphinx.po and extension-specific catalogs)"
      ]
    },
    {
      "subtask": "Add a regression test that verifies a project-level sphinx.po override takes effect",
      "atomics": [
        "Create a minimal test project structure with a locale/xx/LC_MESSAGES/sphinx.po that overrides one string",
        "Write a test that builds the project and asserts the overridden string appears in output, not the shipped translation"
      ]
    }
  ],
  "global_atomics": [
    "Run the existing locale/i18n test suite to confirm no regressions from the reordering change",
    "Verify that the fix works for both gettext_auto_build=True (compiled .mo) and pre-compiled .mo paths"
  ],
  "gold_actions": {
    "global": "Reorder the locale directory list in sphinx/locale/__init__.py (or the init_locale call site in sphinx/application.py) so that entries from app.config.locale_dirs are prepended before the package-internal sphinx/locale path.",
    "subtasks": [
      {
        "subtask": "Locate the catalog-loading code",
        "atomics": [
          "Read sphinx/locale/__init__.py; find get_translation() / init() and the translators dict; read sphinx/application.py and search for calls to sphinx.locale.init or locale_dirs usage",
          "Identify the list construction such as `[path.join(package_dir, 'locale')] + locale_dirs` or equivalent that establishes search priority"
        ]
      },
      {
        "subtask": "Trace the ordering bug",
        "atomics": [
          "Confirm that sphinx/locale (package dir) is inserted at index 0 or iterated first, making it win over user-supplied paths",
          "Verify that GNUTranslations.install or Babel Catalog merging uses first-found or first-merged semantics that make order decisive"
        ]
      },
      {
        "subtask": "Fix the search-path ordering",
        "atomics": [
          "Edit the locale path list construction to place user locale_dirs first: e.g., change `[package_locale] + locale_dirs` to `locale_dirs + [package_locale]` in sphinx/locale/__init__.py init()",
          "Audit all other call sites (e.g., extension locale init) that hard-code the package locale first and apply the same reordering"
        ]
      },
      {
        "subtask": "Add a regression test",
        "atomics": [
          "Under tests/roots/ create test-locale-override/ with conf.py (language='xx'), a dummy locale/xx/LC_MESSAGES/sphinx.po overriding one msgid, and an index.rst that triggers that string",
          "Add a pytest test in tests/test_locale.py (or test_build_html.py) that calls app.build() on the root and asserts the overriding msgstr appears in the rendered HTML"
        ]
      }
    ],
    "global_atomics": [
      "Run `python -m pytest tests/test_locale.py tests/test_intl.py -x` and confirm all pass after the reordering change",
      "Manually verify with the reporter's reproduction repo (sphinx-test-locale-override) that 'Foobar 1' and 'Whatever 1' now appear instead of the shipped Danish strings"
    ]
  }
